class Solution:
    def numSimilarGroups(self, strs):
        n = len(strs)
        def similar(a, b):
            diff = 0
            for x, y in zip(a, b):
                if x != y:
                    diff += 1
                    if diff > 2:
                        return False
            return diff == 0 or diff == 2
        # explicit BFS over the similarity graph, counting components
        seen = [False] * n
        groups = 0
        for i in range(n):
            if seen[i]:
                continue
            groups += 1
            stack = [i]
            seen[i] = True
            while stack:
                u = stack.pop()
                for v in range(n):
                    if not seen[v] and similar(strs[u], strs[v]):
                        seen[v] = True
                        stack.append(v)
        return groups

